C<pre><code>int search(int key, int a[], int begin, int end)
{
    int ret=-1;
    if(begin&lt;end)
    {
        int mid=(begin+end)/2;
        if(key&lt;a[mid])
            ret=search(key, a, begin, mid-1);
        else if(key&gt;a[mid])
            ret=search(key, a, mid+1, end);
        else
            ret=mid;
    }
    else
        printf("FAILED\n");
    return ret;
}
</code></pre>

C<pre><code>void selection_sort(int a[], int n)
{
    for(int i=0;i&lt;n-1;i++)
    {
        int index=i;
        for(int j=i;j&lt;n;j++)
        {
            if(a[index]&gt;a[j])
                index=j;
        }
        int temp=a[index];
        a[index]=a[i];
        a[i]=temp;
    }
}
</code></pre>

C<pre><code>void bubble_sort(int a[], int n)
{
    for(int i=n-1;i&gt;0;i--)
    {
        for(int j=0;j&lt;i;j++)
        {
            if(a[j]&gt;a[j+1])
            {
                int temp=a[j];
                a[j]=a[j+1];
                a[j+1]=temp;
            }
        }
    }
}
</code></pre>

C<pre><code>void insertionSort(int arr[], int n)
{
    for(int i=1;i&lt;n;i++)
    {
        int ele=arr[i];
        int j=i-1;
        while(j&gt;=0&amp;&amp;ele&lt;arr[j])
        {
            arr[j+1]=arr[j];
            j--;
            arr[j+1]=ele;
        }
    }
}
</code></pre>

C<pre><code>void MergeSort(int a[], int lo, int hi)
{
    int md;
    if (lo &lt; hi)
    {
        md = (lo + hi) / 2;
        MergeSort(a, lo, md);
        MergeSort(a, md + 1, hi);
        merge(a, lo, md, hi);
    }
}

void merge(int a[], int lo, int md, int hi)
{
    int i = lo, j = md + 1, k = lo;
    int b[MAXN + 3];

    while (k &lt; hi)
    {
        if (i &lt;= md &amp;&amp; j &lt;= hi)
        {
            if (a[i] &lt;= a[j])
                b[k++] = a[i++];
            else
                b[k++] = a[j++];
        }
        else
            break;
    }

    while (i &lt;= md)
        b[k++] = a[i++];
    while (j &lt;= hi)
        b[k++] = a[j++];

    for (k = lo; k &lt;= hi; k++)
        a[k] = b[k];
}
