C<pre><code>void quicksort_lomuto(int a[], int low, int high)
{
    int pivot;
    if(low&lt;high)
    {
        pivot=partition(a, low, high);
        quicksort_lomuto(a, low, pivot-1);
        quicksort_lomuto(a, pivot+1, high);
    }
}

int partition(int a[], int low, int high)
{
    int pi=a[high];
    int i=low;
    for(int j=low;j&lt;=high;j++)
    {
        if(a[j]&lt;pi)
        {
            int t=a[i];
            a[i]=a[j];
            a[j]=t;
            i++;
        }
    }
    int k=a[i];
    a[i]=a[high];
    a[high]=k;

    return i;
}
</code></pre>

C<pre><code>void quicksort_hoare(int a[], int low, int high)
{
    int pivot;
    if(low&lt;high)
    {
        pivot=partition(a, low, high);
        quicksort_hoare(a, low, pivot-1);
        quicksort_hoare(a, pivot+1, high);
    }
}

int partition(int a[], int low, int high)
{
    int pi=a[low+(high-low)/2];
    int i=low-1;
    int j=high+1;
    while(1)
    {
        do{
            i++;
        }while(a[i]&lt;pi);
        do{
            j--;
        }while(a[j]&gt;pi);

        if(i&lt;=j)
            return j;
        int t=a[i];
        a[i]=a[j];
        a[j]=t;
    }
}
</code></pre>

