List list_create()
{
    List list = {NULL, NULL};
    return list;
}

void list_free(List *list)
{
    for(Node *p=list-&gt;head;p;)
    {
        Node *q=p-&gt;next;
        free(p);
        p=q;
    }
    list-&gt;head=list-&gt;tail=NULL;
}

void list_append(List *list, int v)
{
    Node *p = (Node *)malloc(sizeof(Node));
    p-&gt;value = v;
    p-&gt;next = NULL;
    if (list-&gt;tail)
    {
        list-&gt;tail-&gt;next = p;
        list-&gt;tail = p;
    }
    else
    {
        list-&gt;head = list-&gt;tail = p;
    }
}

void list_insert(List *list, int v)
{
    Node *p = (Node *)malloc(sizeof(Node));
    p-&gt;value = v;
    p-&gt;next = list-&gt;head;
    list-&gt;head = p;
    if (list-&gt;tail == NULL)
    {
        list-&gt;tail = p;
    }
}

int list_find(List *list, int v)
{
    int cnt = 0;
    Node *p = list-&gt;head;
    while (p)
    {
        if (p-&gt;value == v)
        {
            return cnt;
        }
        cnt++;
        p = p-&gt;next;
    }
    return -1;
}

void list_remove(List *list, int v)
{
    for (Node *p = list-&gt;head, *q = NULL; p;)
    {
        if (p-&gt;value == v)
        {
            Node *r = p-&gt;next;
            if (q)
            {
                q-&gt;next = p-&gt;next;
            }
            else
            {
                list-&gt;head = p-&gt;next;
            }
            if (p == list-&gt;tail)
            {
                list-&gt;tail = q;
            }
            free(p);
            p = r;
        }
        else
        {
            q = p;
            p = p-&gt;next;
        }
    }
}
