    }
    printf("\n");
}

void list_clear(List *list)
{
    for ( Node *p = list-&gt;head, *q; p; p=q ) {
        q = p-&gt;next;
        free(p);
    }
}

void list_append(List *list, int value)
{
    Node *p = (Node *)malloc(sizeof(Node));
    p-&gt;value = value;
    if (list-&gt;tail)
    {
        p-&gt;prev = list-&gt;tail;
        list-&gt;tail-&gt;next = p;
        list-&gt;tail = p;
        p-&gt;next = NULL;
    }
    else
    {
        list-&gt;tail = list-&gt;head = p;
        p-&gt;next = p-&gt;prev = NULL;
    }
}

void list_remove(List *list, int value)
{
    for (Node *p = list-&gt;head; p;)
    {
        if (p-&gt;value == value)
        {
            Node *n = p-&gt;next;
            if (p-&gt;prev)
                p-&gt;prev-&gt;next = p-&gt;next;
            else
                list-&gt;head = p-&gt;next;

            if (p-&gt;next)
                p-&gt;next-&gt;prev = p-&gt;prev;
            else
                list-&gt;tail = p-&gt;prev;

            free(p);
            p = n;
        }
        else
            p = p-&gt;next;
    }
}
