C<pre><code>void quicksort(ElementType A[], int N)
{
    if(N&lt;2) return ;
    choose pivot;
    Partition S={A[]\pivot} into :
        A1={a|a&lt;=pivot}, A2={a|a&gt;=pivot};
    A=quicksort(A1)+{pivot}+quicksort(A2);
}
